import{_ as t,o as i,c as n,ag as a}from"./chunks/framework.DTiDeF2Q.js";const r=JSON.parse('{"title":"Bí Danh Tmux | Dotfiles (VI)","titleTemplate":":title","description":"Lệnh tmux rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Tmux | Dotfiles","description":"Lệnh tmux rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Tmux | Dotfiles preview","canonical":"/vi/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Tmux","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/tmux/"},"headers":[],"relativePath":"vi/aliases/tmux/index.md","filePath":"vi/aliases/tmux/index.md","lastUpdated":1773010926000}'),o={name:"vi/aliases/tmux/index.md"};function c(l,e,h,d,s,u){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="bi-danh-tmux" tabindex="-1">Bí Danh Tmux <a class="header-anchor" href="#bi-danh-tmux" aria-label="Permalink to &quot;Bí Danh Tmux&quot;">​</a></h1><p>Lệnh tmux rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 11</li><li>Hàm hỗ trợ: 1</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>tma</code> → <code>&#39;tmux attach-session&#39; # Gắn vào phiên cuối</code></li><li><code>tmat</code> → <code>&#39;tmux attach-session -t&#39; # Gắn vào phiên cụ thể</code></li><li><code>tmi</code> → <code>&#39;tmux info&#39; # Hiện thông tin tmux</code></li><li><code>tmka</code> → <code>&#39;tmux kill-server&#39; # Hủy tất cả phiên (server)</code></li><li><code>tmks</code> → <code>&#39;tmux kill-session -a&#39; # Hủy tất cả phiên trừ phiên hiện tại</code></li><li><code>tml</code> → <code>&#39;tmux list-sessions&#39; # Liệt kê tất cả phiên</code></li><li><code>tmlp</code> → <code>&#39;tmux list-panes&#39; # Liệt kê ngăn</code></li><li><code>tmls</code> → <code>&#39;tmux list-windows&#39; # Liệt kê cửa sổ</code></li><li><code>tmn</code> → <code>&#39;tmux new-session&#39; # Phiên mới không tên</code></li><li><code>tmr</code> → <code>&#39;tmux source ~/.dotfiles/lib/configurations/tmux/tmux&#39; # Tải lại cấu hình</code></li><li><code>tms</code> → <code>&#39;tmux new-session -s&#39; # Phiên mới có tên</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const x=t(o,[["render",c]]);export{r as __pageData,x as default};
